<script lang="ts">export interface ToastMessage { id: string; message: string; tone?: "success"|"warning"|"error"; } interface Props { messages?: ToastMessage[]; onDismiss?: (id: string) => void; } let { messages = [], onDismiss = () => {} }: Props = $props();</script>
<div class="toast-region" aria-live="polite" aria-label="Notifications">{#each messages as message (message.id)}<div class:warning={message.tone==="warning"} class:error={message.tone==="error"} role="status"><span>{message.message}</span><button type="button" aria-label="Dismiss notification" onclick={() => onDismiss(message.id)}>×</button></div>{/each}</div>
<style>.toast-region{position:fixed;z-index:90;right:18px;bottom:18px;display:grid;gap:8px;width:min(360px,calc(100vw - 36px))}.toast-region>div{display:grid;grid-template-columns:1fr auto;align-items:center;gap:10px;border:1px solid var(--color-positive-border);border-radius:var(--radius-surface);background:var(--color-surface);box-shadow:var(--elevation-z2);color:var(--color-positive-text);padding:11px 13px}.warning{color:var(--color-warning-text)!important;border-color:var(--color-warning-border)!important}.error{color:var(--color-danger)!important;border-color:var(--color-danger-border)!important}button{border:0;background:transparent;color:inherit;font-size:1.1rem}</style>
